#pragma once

#include <memory>
#include <string>
#include <vector>

#include "envoy/server/filter_config.h"

#include "source/common/common/logger.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Configuration for header injection rule.
 */
struct HeaderInjectionRule {
  std::string header_name;
  std::string header_value;
  bool inject_on_request = true;
  bool inject_on_response = true;
};

/**
 * Encapsulates the filter configuration with header injection rules.
 */
class Config : public Logger::Loggable<Logger::Id::config> {
public:
  Config(const std::vector<HeaderInjectionRule>& rules) : rules_(rules) {}

  const std::vector<HeaderInjectionRule>& rules() const { return rules_; }

private:
  const std::vector<HeaderInjectionRule> rules_;
};

using ConfigSharedPtr = std::shared_ptr<Config>;

/**
 * Custom Header Injection filter that injects configurable headers into
 * requests and/or responses based on configuration.
 */
class CustomHeaderInjectionFilter : public Http::StreamFilter,
                                    public Logger::Loggable<Logger::Id::filter> {
public:
  CustomHeaderInjectionFilter(const ConfigSharedPtr config) : config_(config) {}
  ~CustomHeaderInjectionFilter() override = default;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
  Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks&) override {}

  // StreamEncoderFilter
  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
    return Http::Filter1xxHeadersStatus::Continue;
  }
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
  Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
    return Http::FilterMetadataStatus::Continue;
  }
  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks&) override {}

private:
  const ConfigSharedPtr config_;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
  // Inject headers into request
  for (const auto& rule : config_->rules()) {
    if (rule.inject_on_request) {
      headers.addCopy(Http::LowerCaseString(rule.header_name), rule.header_value);
    }
  }
  return Http::FilterHeadersStatus::Continue;
}

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
  // Inject headers into response
  for (const auto& rule : config_->rules()) {
    if (rule.inject_on_response) {
      headers.addCopy(Http::LowerCaseString(rule.header_name), rule.header_value);
    }
  }
  return Http::FilterHeadersStatus::Continue;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#pragma once

#include "envoy/server/filter_config.h"

#include "source/extensions/filters/http/common/factory_base.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Config registration for the custom-header-injection filter.
 * @see NamedHttpFilterConfigFactory.
 */
class CustomHeaderInjectionConfig
    : public Common::ExceptionFreeFactoryBase<Protobuf::Empty> {
public:
  CustomHeaderInjectionConfig() : ExceptionFreeFactoryBase("envoy.filters.http.custom_header_injection") {}

private:
  absl::StatusOr<Http::FilterFactoryCb> createFilterFactoryFromProtoTyped(
      const Protobuf::Empty& proto_config, const std::string& stats_prefix,
      Server::Configuration::FactoryContext& context) override;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/config.h"

#include "envoy/registry/registry.h"

#include "source/extensions/filters/http/custom_header_injection/filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

absl::StatusOr<Http::FilterFactoryCb>
CustomHeaderInjectionConfig::createFilterFactoryFromProtoTyped(
    const Protobuf::Empty&, const std::string&,
    Server::Configuration::FactoryContext&) {
  // Create a default configuration with some example headers
  std::vector<HeaderInjectionRule> rules;
  rules.push_back({"x-injected-header", "injected-value", true, true});

  auto config = std::make_shared<Config>(rules);

  return [config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamFilter(
        Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(config)});
  };
}

/**
 * Static registration for the custom-header-injection filter.
 * @see RegisterFactory.
 */
REGISTER_FACTORY(CustomHeaderInjectionConfig, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include <memory>

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "test/mocks/http/mocks.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

using testing::NiceMock;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionFilterTest : public testing::Test {
public:
  void setUpFilter(const std::vector<HeaderInjectionRule>& rules) {
    auto config = std::make_shared<Config>(rules);
    filter_ = std::make_unique<CustomHeaderInjectionFilter>(config);
  }

  std::unique_ptr<CustomHeaderInjectionFilter> filter_;
};

/**
 * Test that request headers are injected correctly.
 */
TEST_F(CustomHeaderInjectionFilterTest, RequestHeaderInjection) {
  std::vector<HeaderInjectionRule> rules = {
      {"x-injected-header", "injected-value", true, false}};
  setUpFilter(rules);

  Http::TestRequestHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, false));
  EXPECT_EQ("injected-value", headers.get_("x-injected-header"));
}

/**
 * Test that response headers are injected correctly.
 */
TEST_F(CustomHeaderInjectionFilterTest, ResponseHeaderInjection) {
  std::vector<HeaderInjectionRule> rules = {
      {"x-response-header", "response-value", false, true}};
  setUpFilter(rules);

  Http::TestResponseHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(headers, false));
  EXPECT_EQ("response-value", headers.get_("x-response-header"));
}

/**
 * Test that headers can be injected in both request and response.
 */
TEST_F(CustomHeaderInjectionFilterTest, BothRequestAndResponseHeaderInjection) {
  std::vector<HeaderInjectionRule> rules = {
      {"x-common-header", "common-value", true, true}};
  setUpFilter(rules);

  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ("common-value", request_headers.get_("x-common-header"));

  Http::TestResponseHeaderMapImpl response_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ("common-value", response_headers.get_("x-common-header"));
}

/**
 * Test that multiple headers can be injected.
 */
TEST_F(CustomHeaderInjectionFilterTest, MultipleHeaderInjection) {
  std::vector<HeaderInjectionRule> rules = {
      {"x-header-1", "value-1", true, false},
      {"x-header-2", "value-2", true, false}};
  setUpFilter(rules);

  Http::TestRequestHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, false));
  EXPECT_EQ("value-1", headers.get_("x-header-1"));
  EXPECT_EQ("value-2", headers.get_("x-header-2"));
}

/**
 * Test that headers are not injected when both flags are false.
 */
TEST_F(CustomHeaderInjectionFilterTest, NoHeaderInjection) {
  std::vector<HeaderInjectionRule> rules = {
      {"x-header", "value", false, false}};
  setUpFilter(rules);

  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ(nullptr, request_headers.get_("x-header"));

  Http::TestResponseHeaderMapImpl response_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ(nullptr, response_headers.get_("x-header"));
}

/**
 * Test that other filter methods return Continue.
 */
TEST_F(CustomHeaderInjectionFilterTest, OtherMethods) {
  std::vector<HeaderInjectionRule> rules;
  setUpFilter(rules);

  Buffer::OwnedImpl data;
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->decodeData(data, false));

  Http::TestRequestTrailerMapImpl request_trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue,
            filter_->decodeTrailers(request_trailers));

  Http::TestResponseTrailerMapImpl response_trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue,
            filter_->encodeTrailers(response_trailers));

  Http::TestResponseHeaderMapImpl continue_headers{{":status", "100"}};
  EXPECT_EQ(Http::Filter1xxHeadersStatus::Continue,
            filter_->encode1xxHeaders(continue_headers));

  Http::MetadataMap metadata_map;
  EXPECT_EQ(Http::FilterMetadataStatus::Continue, filter_->encodeMetadata(metadata_map));

  filter_->onDestroy();
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

