namespace HttpFilters {
namespace CustomHeaderInjection {

absl::StatusOr<Http::FilterFactoryCb>
CustomHeaderInjectionConfig::createFilterFactoryFromProtoTyped(
    const Protobuf::Empty&, const std::string&,
    Server::Configuration::FactoryContext&) {
  // Create a default configuration with some example headers
  std::vector<HeaderInjectionRule> rules;
  rules.push_back({"x-injected-header", "injected-value", true, true});

  auto config = std::make_shared<Config>(rules);

  return [config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamFilter(
        Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(config)});
  };
}

/**
 * Static registration for the custom-header-injection filter.
 * @see RegisterFactory.
 */
REGISTER_FACTORY(CustomHeaderInjectionConfig, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

