#include <memory>

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "test/mocks/http/mocks.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

using testing::NiceMock;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionFilterTest : public testing::Test {
public:
  void setUpFilter(const std::vector<HeaderInjectionRule>& rules) {
    auto config = std::make_shared<Config>(rules);
    filter_ = std::make_unique<CustomHeaderInjectionFilter>(config);
  }

  std::unique_ptr<CustomHeaderInjectionFilter> filter_;
};

/**
 * Test that request headers are injected correctly.
 */
TEST_F(CustomHeaderInjectionFilterTest, RequestHeaderInjection) {
  std::vector<HeaderInjectionRule> rules = {
      {"x-injected-header", "injected-value", true, false}};
  setUpFilter(rules);

  Http::TestRequestHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, false));
  EXPECT_EQ("injected-value", headers.get_("x-injected-header"));
}

/**
 * Test that response headers are injected correctly.
 */
TEST_F(CustomHeaderInjectionFilterTest, ResponseHeaderInjection) {
  std::vector<HeaderInjectionRule> rules = {
      {"x-response-header", "response-value", false, true}};
  setUpFilter(rules);

  Http::TestResponseHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(headers, false));
  EXPECT_EQ("response-value", headers.get_("x-response-header"));
}

/**
 * Test that headers can be injected in both request and response.
 */
TEST_F(CustomHeaderInjectionFilterTest, BothRequestAndResponseHeaderInjection) {
  std::vector<HeaderInjectionRule> rules = {
      {"x-common-header", "common-value", true, true}};
  setUpFilter(rules);

  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ("common-value", request_headers.get_("x-common-header"));

  Http::TestResponseHeaderMapImpl response_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ("common-value", response_headers.get_("x-common-header"));
}

/**
 * Test that multiple headers can be injected.
 */
TEST_F(CustomHeaderInjectionFilterTest, MultipleHeaderInjection) {
  std::vector<HeaderInjectionRule> rules = {
      {"x-header-1", "value-1", true, false},
      {"x-header-2", "value-2", true, false}};
  setUpFilter(rules);

  Http::TestRequestHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, false));
  EXPECT_EQ("value-1", headers.get_("x-header-1"));
  EXPECT_EQ("value-2", headers.get_("x-header-2"));
}

/**
 * Test that headers are not injected when both flags are false.
 */
TEST_F(CustomHeaderInjectionFilterTest, NoHeaderInjection) {
  std::vector<HeaderInjectionRule> rules = {
      {"x-header", "value", false, false}};
  setUpFilter(rules);

  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ(nullptr, request_headers.get_("x-header"));

  Http::TestResponseHeaderMapImpl response_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ(nullptr, response_headers.get_("x-header"));
}

/**
 * Test that other filter methods return Continue.
 */
TEST_F(CustomHeaderInjectionFilterTest, OtherMethods) {
  std::vector<HeaderInjectionRule> rules;
  setUpFilter(rules);

  Buffer::OwnedImpl data;
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->decodeData(data, false));

  Http::TestRequestTrailerMapImpl request_trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue,
            filter_->decodeTrailers(request_trailers));

  Http::TestResponseTrailerMapImpl response_trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue,
            filter_->encodeTrailers(response_trailers));

  Http::TestResponseHeaderMapImpl continue_headers{{":status", "100"}};
  EXPECT_EQ(Http::Filter1xxHeadersStatus::Continue,
            filter_->encode1xxHeaders(continue_headers));

  Http::MetadataMap metadata_map;
  EXPECT_EQ(Http::FilterMetadataStatus::Continue, filter_->encodeMetadata(metadata_map));

  filter_->onDestroy();
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

